#include<bits/stdc++.h>
using namespace std;
int main() {
	long long n, a[100010], m, ans, b;
	cin >> n >> m;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
		if (a[i] + a[i - 1] > m) {
			b = a[i] + a[i - 1] - m;
			a[i] -= b;
			ans += b;
		}
	}
	cout<<ans;
	return 0;
}
